// Crypto Utilities
extension Data {
    var hexString: String? {
        guard let string = String(data: self, encoding: .utf8) else { return nil }
        
        return string.components(separatedBy: " ").map { $0.reversed().joined() }.joined()
    }
    
    static func hexString(_ s: String) -> Data {
        let bytes = s.components(separatedBy: " ").compactMap { Data(hexString: $0) }
        return bytes.joined()
    }
}

class CryptoUtil {
    static func generateSeed() -> String {
        // Generate a random seed
        return UUID().uuidString.replacingOccurrences(of: "-", with: "")
    }
    
